 using Microsoft.ML;
 using Microsoft.ML.Data;
 using TicketClassifier.Models;

 namespace TicketClassifier.Services;

 public class TicketClassifierService
 {
     private readonly MLContext _mlContext;
     private readonly ITransformer _model;
     private readonly PredictionEngine<TicketData, TicketPrediction> _predictionEngine;
     private readonly EvaluationResult _evaluationResult;
     private readonly string[] _categoryLabels;

     public TicketClassifierService(string dataPath)
     {
         _mlContext = new MLContext(seed: 0);

         IDataView dataView = _mlContext.Data.LoadFromTextFile<TicketData>(
             dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

         var pipeline = _mlContext.Transforms.Conversion
                 .MapValueToKey("Label", nameof(TicketData.Category))
             .Append(_mlContext.Transforms.Text.FeaturizeText("SubjectFeaturized", nameof(TicketData.Subject)))
             .Append(_mlContext.Transforms.Text.FeaturizeText("DescriptionFeaturized", nameof(TicketData.Description)))
             .Append(_mlContext.Transforms.Concatenate("Features",
                 "SubjectFeaturized", "DescriptionFeaturized", nameof(TicketData.Priority)))
             .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
             .Append(_mlContext.MulticlassClassification.Trainers.SdcaMaximumEntropy())
             .Append(_mlContext.Transforms.Conversion.MapKeyToValue("PredictedLabel"));

         _model = pipeline.Fit(dataView);

         // Extract category labels from the trained model's key-value mapping
         var transformedData = _model.Transform(dataView);
         var labelColumn = transformedData.Schema["Label"];
         var keyValues = new VBuffer<ReadOnlyMemory<char>>();
         labelColumn.GetKeyValues(ref keyValues);
         _categoryLabels = keyValues.Items().OrderBy(v => v.Key).Select(v => v.Value.ToString()).ToArray();

         // Evaluate using cross-validation on the full dataset
         var cvResults = _mlContext.MulticlassClassification
             .CrossValidate(dataView, pipeline, numberOfFolds: 3);

         _evaluationResult = new EvaluationResult
         {
             MacroAccuracy = cvResults.Average(r => r.Metrics.MacroAccuracy),
             MicroAccuracy = cvResults.Average(r => r.Metrics.MicroAccuracy),
             LogLoss = cvResults.Average(r => r.Metrics.LogLoss),
             LogLossReduction = cvResults.Average(r => r.Metrics.LogLossReduction)
         };

         _predictionEngine = _mlContext.Model
             .CreatePredictionEngine<TicketData, TicketPrediction>(_model);
     }

     public PredictionResult Predict(TicketRequest request)
     {
         var ticket = new TicketData
         {
             Subject = request.Subject,
             Description = request.Description,
             Priority = request.Priority
         };

         var prediction = _predictionEngine.Predict(ticket);

         var confidence = new Dictionary<string, float>();
         for (int i = 0; i < _categoryLabels.Length; i++)
         {
             confidence[_categoryLabels[i]] = prediction.Score[i];
         }

         return new PredictionResult
         {
             PredictedCategory = prediction.PredictedCategory,
             Confidence = confidence
         };
     }

     public EvaluationResult GetEvaluationMetrics() => _evaluationResult;
 }

