// Aggregate per-category precision/recall from all CV folds
var perCategoryMetrics = new Dictionary<string, (List<double> P, List<double> R)>();
foreach (var fold in cvResults)
{
    for (int i = 0; i < fold.Metrics.PerClassLogLoss.Count && i < _categoryLabels.Length; i++)
    {
        if (!perCategoryMetrics.ContainsKey(_categoryLabels[i]))
            perCategoryMetrics[_categoryLabels[i]] = (new List<double>(), new List<double>());
    }
    var confMatrix = fold.Metrics.ConfusionMatrix;
    for (int i = 0; i < confMatrix.PerClassPrecision.Count && i < _categoryLabels.Length; i++)
    {
        perCategoryMetrics[_categoryLabels[i]].P.Add(confMatrix.PerClassPrecision[i]);
        perCategoryMetrics[_categoryLabels[i]].R.Add(confMatrix.PerClassRecall[i]);
    }
}

_evaluationResult = new EvaluationResult
{
    MacroAccuracy = cvResults.Average(r => r.Metrics.MacroAccuracy),
    MicroAccuracy = cvResults.Average(r => r.Metrics.MicroAccuracy),
    LogLoss = cvResults.Average(r => r.Metrics.LogLoss),
    LogLossReduction = cvResults.Average(r => r.Metrics.LogLossReduction),
    PerCategory = perCategoryMetrics.Select(kv => new CategoryMetric
    {
        Category = kv.Key,
        Precision = kv.Value.P.Average(),
        Recall = kv.Value.R.Average()
    }).ToList()
};

